  metadatas: [{ law_name: prev.law_name, law_id: prev.law_id }],
  chunk_id: prev.chunk_id,
  law_name: prev.law_name
};

// ====================================================================
// تصنيفات أم القرى للسحب
// ====================================================================
const UQN_BASE = 'https://www.uqn.gov.sa';
const PAGES_PER_CATEGORY = 3; // أول 3 صفحات (الأحدث)

const categories = [
  {
    key: 'rules',
    name: 'لوائح وأنظمة',
    listPath: '/decisions/rules-and-regulations',
    type: 'regulation'
  },
  {
    key: 'cabinet',
    name: 'قرارات مجلس الوزراء',
    listPath: '/decisions/council-of-ministers-decisions',
    type: 'cabinet_decision'
  },
  {
    key: 'royal_decrees',
    name: 'مراسيم ملكية',
    listPath: '/decisions/royal-decrees',
    type: 'royal_decree'
  },
  {
    key: 'royal_orders',
    name: 'أوامر ملكية',
    listPath: '/decisions/royal-orders',
    type: 'royal_order'
  },
  {
    key: 'ministerial',
    name: 'قرارات وزارية',
    listPath: '/decisions/ministerial-decisions',
    type: 'ministerial_decision'
  }
];

// Generate page URLs to scrape
const pageRequests = [];
for (const cat of categories) {
  for (let page = 1; page <= PAGES_PER_CATEGORY; page++) {
    pageRequests.push({
      json: {
        category_key: cat.key,
        category_name: cat.name,
        category_type: cat.type,
        page_number: page,
        list_url: `${UQN_BASE}${cat.listPath}?pgno=${page}`,
        base_url: UQN_BASE
      }
    });
  }
}

return pageRequests;

// ====================================================================
// استخراج روابط الأنظمة من صفحة القائمة
// ====================================================================
const batchItem = $('🔄 صفحة تلو الأخرى').item.json;
const categoryKey = batchItem.category_key;
const categoryType = batchItem.category_type;
const categoryName = batchItem.category_name;

let html = '';
if (typeof $json === 'string') html = $json;
else if ($json.data && typeof $json.data === 'string') html = $json.data;
else html = JSON.stringify($json);

// Extract regulation links with title attribute
// Format: <a href=".../decisions-and-regulations/[subpath/]DIGITS" title="TITLE">
const titlePattern = /<a[^>]*href="(?:https?:\/\/www\.uqn\.gov\.sa)?(\/decisions-and-regulations\/(?:[^\/"]+\/)?([0-9]+))"[^>]*title="([^"]+)"/gi;

const items = [];
const seen = new Set();
let match;

while ((match = titlePattern.exec(html)) !== null) {
  const fullPath = match[1];
  const uqnId = match[2];
  let title = match[3].replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/\s+/g, ' ').trim();

  if (!seen.has(uqnId) && title.length > 3) {
    seen.add(uqnId);
    items.push({
      json: {
        uqn_id: uqnId,
        title: title,
        detail_url: `https://www.uqn.gov.sa${fullPath}`,
        category_key: categoryKey,
        category_type: categoryType,
        category_name: categoryName,
        source: 'uqn.gov.sa'
      }
    });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, reason: `لا توجد عناصر في ${categoryName} صفحة ${batchItem.page_number}` } }];
}

return items;

// ====================================================================
// فحص ChromaDB - أي أنظمة أم القرى موجودة بالفعل؟
// ====================================================================
const CHROMADB = 'http://chromadb:8000/api/v1';
const COLLECTION_NAME = 'saleh_knowledge';

// Get collection
const cols = await fetch(`${CHROMADB}/collections`).then(r => r.json());
const col = cols.find(c => c.name === COLLECTION_NAME);
if (!col) throw new Error('Collection saleh_knowledge not found!');

// Get all metadatas
const total = await fetch(`${CHROMADB}/collections/${col.id}/count`).then(r => r.json());
const data = await fetch(`${CHROMADB}/collections/${col.id}/get`, {
  method: 'POST',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({ include: ['metadatas'], limit: total })
}).then(r => r.json());

// Build set of existing UQN IDs
const existingUqnIds = new Set();
for (const meta of (data.metadatas || [])) {
  if (meta.source === 'uqn.gov.sa' && meta.uqn_id) {
    existingUqnIds.add(String(meta.uqn_id));
  }
}

// Filter input items
const inputItems = $input.all();
const newItems = inputItems.filter(item => {
  if (item.json.skip) return false;
  return !existingUqnIds.has(String(item.json.uqn_id));
});

if (newItems.length === 0) {
  return [{ json: { status: 'up_to_date', message: '✅ لا يوجد جديد في أم القرى', total_in_db: total, checked: inputItems.length, existing_uqn: existingUqnIds.size } }];
}

console.log(`🆕 Found ${newItems.length} new items from UQN out of ${inputItems.length}`);
return newItems;

// ====================================================================
// استخراج نص النظام وتقسيمه
// ====================================================================
const chunkSize = 1000;
const overlap = 150;
const results = [];

const batchNode = $('🔄 معالجة نظام تلو الآخر');
const meta = batchNode.item.json;
const title = meta.title || 'unknown';
const uqnId = meta.uqn_id || 'unknown';
const categoryType = meta.category_type || 'regulation';
const categoryName = meta.category_name || '';

let html = '';
if (typeof $json === 'string') html = $json;
else if ($json.data && typeof $json.data === 'string') html = $json.data;
else html = JSON.stringify($json);

// === تنظيف HTML ===
let text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<br\s*\/?>/gi, '\n');
text = text.replace(/<\/p>/gi, '\n\n');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
text = text.replace(/[ \t]+/g, ' ');

// === البحث عن بداية النص ===
const markers = ['المادة الأولى', 'المادة الاولى', 'مادة أولى', title];
for (const m of markers) {
  const idx = text.indexOf(m);
  if (idx > -1 && idx < text.length * 0.5) {
    text = text.substring(idx);
    break;
  }
}

// === إزالة الذيل (Footer) ===
const footerMarkers = ['الأكثر قراءة', 'جميع الحقوق محفوظة', 'تابعنا على', 'اتصل بنا', 'خريطة الموقع'];
for (const m of footerMarkers) {
  const idx = text.indexOf(m);
  if (idx > 200) {
    text = text.substring(0, idx);
    break;
  }
}

// تنظيف السطور
text = text.split('\n').map(l => l.trim()).filter(l => l.length > 0).join('\n');
text = text.replace(/\n{3,}/g, '\n\n').trim();

if (text.length < 100) {
  return [{ json: { error: `النص قصير جداً: ${title}`, length: text.length, uqn_id: uqnId } }];
}

// === التقسيم (مع مراعاة حدود المواد) ===
const articlePattern = /(?=المادة\s+(?:الأولى|الثانية|الثالثة|الرابعة|الخامسة|السادسة|السابعة|الثامنة|التاسعة|العاشرة|الحادية|[\d\u0660-\u0669]+))/;
const articleSplits = text.split(articlePattern);

let chunks = [];
if (articleSplits.length > 3) {
  // Article-based chunking
  let currentChunk = '';
  for (const part of articleSplits) {
    const trimmed = part.trim();
    if (!trimmed) continue;
    if (currentChunk.length + trimmed.length < chunkSize) {
      currentChunk += (currentChunk ? '\n\n' : '') + trimmed;
    } else {
      if (currentChunk) chunks.push(currentChunk.trim());
      currentChunk = trimmed;
    }
  }
  if (currentChunk) chunks.push(currentChunk.trim());
} else {
  // Size-based chunking
  let start = 0, idx = 0;
  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    const chunk = text.substring(start, end).trim();
    if (chunk.length > 50) chunks.push(chunk);
    if (end >= text.length) break;
    start += chunkSize - overlap;
  }
}

// === إنشاء النتائج ===
for (let i = 0; i < chunks.length; i++) {
  results.push({
    json: {
      chunk_id: `uqn_${uqnId}_c${i}`,
      chunk_text: chunks[i],
      title: title,
      uqn_id: uqnId,
      source: 'uqn.gov.sa',
      source_url: meta.detail_url || '',
      category: categoryType,
      category_name: categoryName,
      chunk_index: i,
      total_chunks: chunks.length,
      total_text_length: text.length
    }
  });
}

if (results.length === 0) {
  return [{ json: { error: `فشل التقسيم: ${title}`, uqn_id: uqnId } }];
}

return results;

const embedding = $json.embedding;
const prev = $('✂️ استخراج وتقسيم النص').item.json;

return {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{
    law_name: prev.title,
    uqn_id: prev.uqn_id,
    source: 'uqn.gov.sa',
    source_url: prev.source_url || '',
    category: prev.category,
    chunk_index: prev.chunk_index,
    total_chunks: prev.total_chunks,
    ingested_at: new Date().toISOString(),
    auto_updated: 'true'
  }],
  chunk_id: prev.chunk_id,
  title: prev.title
};

// ====================================================================
// تقرير نهائي
// ====================================================================
const items = $input.all();
const successCount = items.filter(i => !i.json.error).length;
const errorCount = items.filter(i => i.json.error).length;
const timestamp = new Date().toISOString();

let finalCount = 'N/A';
try {
  const resp = await fetch('http://chromadb:8000/api/v1/collections/86fce70f-0753-4989-9e4c-54d1ded405cd/count');
  finalCount = await resp.json();
} catch(e) {}

return [{
  json: {
    status: 'completed',
    source: 'uqn.gov.sa - أم القرى',
    total_chunks_saved: successCount,
    errors: errorCount,
    chromadb_total: finalCount,
    message: `📰 أم القرى: تم حفظ ${successCount} قطعة جديدة | أخطاء: ${errorCount} | الإجمالي: ${finalCount}`,
    timestamp: timestamp
  }
}];

// ====================================================================
// القائمة الشاملة للأنظمة السعودية - 50+ نظام
// ====================================================================
const laws = [
  // === الأنظمة الأساسية ===
  { law_id: '16b97fcb-4833-4f66-8531-a9a700f161b6', law_name: 'النظام الأساسي للحكم', category: 'constitutional' },
  { law_id: 'b5cf540a-e6ac-426a-b348-a9a700f163de', law_name: 'نظام مجلس الشورى', category: 'constitutional' },
  { law_id: '93e87aa7-f344-4711-b97c-a9a700f1662b', law_name: 'نظام مجلس الوزراء', category: 'constitutional' },
  { law_id: '93f81644-fbbc-49ca-b33c-a9a700f16701', law_name: 'نظام المناطق', category: 'regions' },

  // === القضاء والمرافعات (verified IDs) ===
  { law_id: 'ea1765a3-dec3-41a0-a32f-a9a700f26d58', law_name: 'نظام القضاء', category: 'judiciary' },
  { law_id: 'f0eaae46-9f84-40ee-815e-a9a700f268b3', law_name: 'نظام المرافعات الشرعية', category: 'litigation' },
  { law_id: '9a0249b7-f835-48fa-8d1e-a9a700f1981a', law_name: 'نظام الإجراءات الجزائية', category: 'criminal_procedure' },
  { law_id: 'd7e8efd3-4021-4413-8255-ae7c00f190de', law_name: 'نظام التنفيذ', category: 'execution_law' },
  { law_id: '2716057c-c097-4bad-8e1e-ae1400c678d5', law_name: 'نظام الإثبات', category: 'evidence_law' },
  { law_id: '12752a60-2a4a-4cab-a05d-a9a700f274a5', law_name: 'نظام التحكيم', category: 'arbitration' },
  { law_id: '4d72d829-947b-45d5-b9b5-ae5800d6bac2', law_name: 'نظام الأحوال الشخصية', category: 'personal_status' },

  // === العمل والتوظيف ===
  { law_id: '08381293-6388-48e2-8ad2-a9a700f2aa94', law_name: 'نظام العمل', category: 'labor_law' },
  { law_id: 'eaee8a20-3a54-4aaf-b0d9-b1ad00998962', law_name: 'نظام التأمينات الاجتماعية', category: 'social_insurance' },
  { law_id: '32f651e6-2976-439c-b418-a9a700f23fb2', law_name: 'نظام الخدمة المدنية', category: 'civil_service' },

  // === التجارة والشركات ===
  { law_id: 'a8376aea-1bc3-49d4-9027-aed900b555af', law_name: 'نظام الشركات', category: 'companies_law' },
