if (typeof $json === 'string') html = $json;
else if ($json.data && typeof $json.data === 'string') html = $json.data;
else html = JSON.stringify($json);

// تنظيف HTML
let text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
text = text.replace(/\s+/g, ' ').trim();

const markers = ['نـــص النظـــام', 'نص النظام', 'المادة الأولى'];
for (const m of markers) {
  const idx = text.indexOf(m);
  if (idx > -1) { text = text.substring(idx); break; }
}

for (const m of ['جميع الحقوق محفوظة', 'go to top', 'Additional Links']) {
  const idx = text.indexOf(m);
  if (idx > -1) text = text.substring(0, idx);
}
text = text.trim();

if (text.length < 100) {
  return [{ json: { error: `النص قصير جداً: ${lawName}`, length: text.length, law_name: lawName } }];
}

let start = 0, chunkIdx = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 50) {
    results.push({
      json: {
        chunk_id: `boe_${category}_${lawId.substring(0,8)}_c${chunkIdx}`,
        chunk_text: chunk,
        law_name: lawName,
        law_id: lawId,
        source: source,
        category: category,
        chunk_index: chunkIdx,
        total_text_length: text.length
      }
    });
    chunkIdx++;
  }
  if (end >= text.length) break;
  start += chunkSize - overlap;
}

return results;

