  const chunk = words.slice(i, i + chunkSize).join(' ');
  if (chunk.trim().length > 80) {
    chunks.push({
      json: {
        text: chunk,
        metadata: {
          source: fileName,
          chunk_index: chunks.length,
          file_type: fileExt,
          ingested_at: new Date().toISOString()
        }
      }
    });
  }
}

return chunks.length > 0 ? chunks : [{ json: { skip: true, reason: 'لا chunks كافية', file: fileName } }];

