// استخراج نص القانون من HTML وتقسيمه إلى أجزاء
const chunkSize = 800;
const overlap = 100;
const results = [];

// الحصول على بيانات القانون من SplitInBatches
const batchNode = $('🔄 معالجة واحد تلو الآخر');
const meta = batchNode.item.json;
const lawName = meta.law_name || 'unknown';
const lawId = meta.law_id || 'unknown';
const source = meta.source || 'boe.gov.sa';
const category = meta.category || '';

// الحصول على HTML من HTTP Response
let html = '';
if (typeof $json === 'string') {
  html = $json;
} else if ($json.data && typeof $json.data === 'string') {
  html = $json.data;
} else {
  html = JSON.stringify($json);
}

// تنظيف HTML
let text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"');
text = text.replace(/\s+/g, ' ').trim();

// البحث عن بداية نص النظام
const markers = ['نـــص النظـــام', 'نص النظام', 'المادة الأولى'];
let startIdx = -1;
for (const m of markers) {
  startIdx = text.indexOf(m);
  if (startIdx > -1) break;
}
if (startIdx > -1) text = text.substring(startIdx);

// إزالة الفوتر
const footerMarkers = ['جميع الحقوق محفوظة', 'go to top', 'Additional Links'];
for (const m of footerMarkers) {
  const idx = text.indexOf(m);
  if (idx > -1) text = text.substring(0, idx);
}
text = text.trim();

if (text.length < 100) {
  return [{ json: { error: `النص قصير جداً: ${lawName}`, length: text.length } }];
}

// تقسيم النص
let start = 0, chunkIdx = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 50) {
    results.push({
      json: {
        chunk_id: `boe_${category}_c${chunkIdx}`,
        chunk_text: chunk,
        law_name: lawName,
        law_id: lawId,
        source: source,
        category: category,
        chunk_index: chunkIdx,
        total_text_length: text.length
      }
    });
    chunkIdx++;
  }
  if (end >= text.length) break;
  start += chunkSize - overlap;
}

return results;

// دمج بيانات Embedding مع بيانات القطعة
const embedding = $json.embedding;
const prev = $('✂️ استخراج وتقسيم النص').item.json;

return {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{
    law_name: prev.law_name,
    law_id: prev.law_id,
    source: prev.source,
    category: prev.category,
    chunk_index: prev.chunk_index,
    ingested_at: new Date().toISOString()
  }],
  chunk_id: prev.chunk_id,
  law_name: prev.law_name
};

